```swift
import Foundation
import Combine

class TimeProvider: ObservableObject {
    @Published var currentTime: Date = Date()

    private var timer: Timer?

    init() {
        startTimer()
    }

    func startTimer() {
        // Update at 100Hz (every 0.01 seconds) for smooth animation
        timer = Timer.scheduledTimer(withTimeInterval: 0.01, repeats: true) { [weak self] _ in
            self?.currentTime = Date()
        }
    }

    func stopTimer() {
        timer?.invalidate()
        timer = nil
    }

    deinit {
        stopTimer()
    }

    // Calculate hand angles based on current time
    func hourAngle(for date: Date = Date()) -> Double {
        let calendar = Calendar.current
        let hour = calendar.component(.hour, from: date)
        let minute = calendar.component(.minute, from: date)
        let second = calendar.component(.second, from: date)

        // Convert to 12-hour format
        let hour12 = hour % 12

        // Calculate smooth hour hand movement
        // Each hour = 30 degrees, each minute = 0.5 degrees, each second = 0.5/60 degrees
        let degrees = Double(hour12) * 30.0 + Double(minute) * 0.5 + Double(second) * (0.5 / 60.0)

        // Subtract 90 to start at 12 o'clock (top)
        return degrees - 90.0
    }

    func minuteAngle(for date: Date = Date()) -> Double {
        let calendar = Calendar.current
        let minute = calendar.component(.minute, from: date)
        let second = calendar.component(.second, from: date)

        // Each minute = 6 degrees, each second = 0.1 degrees
        let degrees = Double(minute) * 6.0 + Double(second) * 0.1

        // Subtract 90 to start at 12 o'clock (top)
        return degrees - 90.0
    }

    func secondAngle(for date: Date = Date()) -> Double {
        let calendar = Calendar.current
        let second = calendar.component(.second, from: date)
        let nanosecond = calendar.component(.nanosecond, from: date)

        // Each second = 6 degrees, smooth sub-second movement
        let degrees = Double(second) * 6.0 + (Double(nanosecond) / 1_000_000_000.0) * 6.0

        // Subtract 90 to start at 12 o'clock (top)
        return degrees - 90.0
    }
}
```

### Key Design Decisions

1. **Update Frequency**: 100Hz (0.01s intervals) matches ContentView's timer for smooth animation
2. **Smooth Movement**: 
   - Hour hand moves gradually based on minutes and seconds
   - Minute hand moves gradually based on seconds
   - Second hand uses nanosecond precision for ultra-smooth sweep
3. **Angle Calculations**:
   - Hour: 30° per hour + 0.5° per minute + (0.5/60)° per second
   - Minute: 6° per minute + 0.1° per second
   - Second: 6° per second + sub-second interpolation
4. **Coordinate System**: All angles subtract 90° to align 0° with 12 o'clock position (top)

### Integration with ContentView

The ContentView will need to be updated to use TimeProvider instead of its current timer. The TimeProvider will be passed to ClockView for rendering the hands.

### Testing

After implementation, verify:
